/* wms-inventory-ivatmanager-sql-oracle.xml - selectIvatInfoMap - 재고 속성 조회 */
SELECT *
  FROM TWORK_INFO_IVAT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{OWKEY}, #{sowkey})
   AND ICKEY = #{ickey}
   AND (EXPDATE = #{expdate} OR (EXPDATE IS NULL AND #{expdate} IS NULL))
   AND (PRDCTDATE = #{prdctdate} OR (PRDCTDATE IS NULL AND #{prdctdate} IS NULL))
